export function initializeFirebase(
    config: object,
    firebase: any,
    database: any,
    firestore: any,
    functions: any,
    remoteConfig: any,
    auth: any
  ) {
    if (!firebase.apps.length) {
      firebase.initializeApp(config);
    }
  
    // Export modules
    const firebaseModules: FireBaseModules = {
      database,
      firestore,
      functions,
      remoteConfig,
      auth
    };
    
    return firebaseModules;
  }
  
  // Define the FireBaseModules interface in the same file or another type definitions file
  export interface FireBaseModules {
    database: any;
    firestore: any;
    functions: any;
    remoteConfig: any;
    auth: any;
  }
  